515	            .tm-bars span:nth-child(5) { animation-delay: 0.48s; }
516	            @keyframes tm-bar {
517	              0%, 100% { height: 30%; }
518	              50%      { height: 100%; }
519	            }
520	            /* Orb on the left: solid core + two expanding rings */
521	            .tm-orb {
522	              position: relative;
523	              width: 42px;
524	              height: 42px;
525	              flex-shrink: 0;
526	            }
527	            .tm-orb-core {
528	              position: absolute;
529	              inset: 12px;
530	              border-radius: 999px;
531	              background: radial-gradient(circle at 35% 30%, #93c5fd, #2563eb 70%);
532	              box-shadow: 0 0 18px rgba(37,99,235,0.6);
