547	            .tm-card-error .tm-orb-ring { border-color: rgba(185,28,28,0.6); }
548	            @keyframes tm-orb-pulse {
549	              0%, 100% { transform: scale(0.92); opacity: 0.85; }
550	              50%      { transform: scale(1.08); opacity: 1;    }
551	            }
552	            @keyframes tm-orb-ring {
553	              0%   { transform: scale(0.55); opacity: 0.85; }
554	              80%  { opacity: 0; }
555	              100% { transform: scale(1.6);  opacity: 0; }
556	            }
557	            .tm-ellipsis::after {
558	              content: '';
559	              display: inline-block;
560	              width: 1.4em;
561	              text-align: left;
562	              animation: tm-dots 1.4s steps(4, end) infinite;
563	              vertical-align: bottom;
564	              padding-left: 2px;
565	            }
566	            @keyframes tm-dots {
567	              0%   { content: ''; }
568	              25%  { content: '.'; }
569	              50%  { content: '..'; }
570	              75%, 100% { content: '...'; }
571	            }
572	            @keyframes tm-shimmer {
573	              0%   { background-position: 100% 0; }
574	              100% { background-position: -100% 0; }
575	            }
576	            @keyframes tm-text-shine {
577	              0%   { background-position: 200% 0; }
578	              100% { background-position: -200% 0; }
579	            }
580	          `}</style>
581	        </Html>
582	      )}
583	    </group>
584	  );
585	}
586	
587	// ─── Loaded GLB ────────────────────────────────────────────────────────────
588	// Trellis returns a free-form GLB at arbitrary scale and pivot. We center it
589	// on the origin and uniformly scale it so the longest XZ side matches the
590	// current footprint width — that keeps panels (placed by <Panels/> using the
591	// HouseGeometry footprint) aligned on the model's roof.
592	
593	function LoadedGlb({
594	  url,
595	  width,
596	  depth,
597	  height,
598	  opacity = 1,
599	}: {
600	  url: string;
601	  width: number;
602	  depth: number;
603	  height: number;
604	  /** Multiplied into every mesh material's opacity for the morph fade-in. */
605	  opacity?: number;
606	}) {
607	  const gltf = useLoader(GLTFLoader, url);
608	  const scene = useMemo(() => gltf.scene.clone(true), [gltf]);
609	
610	  const { scale, offset } = useMemo(() => {
611	    const box = new Box3().setFromObject(scene);
612	    const size = new Box3().setFromObject(scene).getSize(new Vector3());
613	    const center = box.getCenter(new Vector3());
614	    const targetXZ = Math.max(width, depth);
615	    const sourceXZ = Math.max(size.x, size.z, 0.001);
616	    const s = targetXZ / sourceXZ;
617	    return {
618	      scale: s,
619	      // Recenter to origin on XZ, drop Y so the model sits on y=0.
620	      offset: new Vector3(-center.x * s, -box.min.y * s, -center.z * s),
621	    };
622	  }, [scene, width, depth]);
623	
624	  // Cast/receive shadows on every mesh + flip materials transparent so the
625	  // opacity fade-in works during the morph.
626	  useEffect(() => {
627	    scene.traverse((obj) => {
628	      const mesh = obj as Mesh;
629	      if (!mesh.isMesh) return;
630	      mesh.castShadow = true;
631	      mesh.receiveShadow = true;
632	      const mats = Array.isArray(mesh.material) ? mesh.material : [mesh.material];
633	      for (const m of mats) {
634	        if (m && 'transparent' in m) m.transparent = true;
635	      }
636	    });
637	  }, [scene]);
638	
639	  // Drive the opacity each frame (cheaper than a re-render on every step).
640	  useFrame(() => {
641	    scene.traverse((obj) => {
642	      const mesh = obj as Mesh;
643	      if (!mesh.isMesh) return;
644	      const mats = Array.isArray(mesh.material) ? mesh.material : [mesh.material];
645	      for (const m of mats) {
646	        if (m && 'opacity' in m) (m as { opacity: number }).opacity = opacity;
647	      }
648	    });
649	  });
650	
651	  // Use the height from the house geometry only as a sanity check — Trellis
652	  // GLBs already encode their own roof height correctly relative to their
653	  // footprint, so we keep the uniform scale.
654	  void height;
655	
656	  return <primitive object={scene} scale={scale} position={offset} />;
657	}
658	
659	function Ground() {
660	  return (
661	    <mesh position={[0, 0, 0]} rotation={[-Math.PI / 2, 0, 0]} receiveShadow>
662	      <planeGeometry args={[40, 40]} />
663	      <meshStandardMaterial color="#e7e2d9" roughness={0.95} />
664	    </mesh>
665	  );
666	}
667	
668	// ─── Resolve current address ───────────────────────────────────────────────
669	
670	function useResolvedCoords(houseId: HouseId | 'custom'): { lat: number; lng: number } | null {
671	  const customAddress = useStore((s) => s.customAddress);
672	  return useMemo(() => {
673	    if (houseId === 'custom') {
674	      return customAddress ? { lat: customAddress.lat, lng: customAddress.lng } : null;
675	    }
676	    const c = HOUSE_COORDS[houseId];
677	    return c ? { lat: c.lat, lng: c.lng } : null;
678	  }, [houseId, customAddress]);
679	}
680

