2	// aerial screenshot, returning a fal-hosted URL of the cleaned image
3	// (target building only, white background) ready for fal-ai/trellis.
4	//
5	// Body: { lat: number, lng: number, zoom?: number }
6	// Resp: { ok: true, imageUrl } | { ok: false, error }
7	
8	import { NextResponse, type NextRequest } from 'next/server';
9	import { cleanBuildingImage } from '@/lib/fal';
10	
11	export const runtime = 'nodejs';
12	export const maxDuration = 300;
13	
14	export async function POST(req: NextRequest) {
15	  let body: { lat?: number; lng?: number; zoom?: number } = {};
16	  try {
17	    body = await req.json();
18	  } catch {
19	    return NextResponse.json({ ok: false, error: 'Invalid JSON body' }, { status: 400 });
20	  }
21	
22	  const lat = Number(body.lat);
23	  const lng = Number(body.lng);
24	  if (!Number.isFinite(lat) || !Number.isFinite(lng)) {
25	    return NextResponse.json({ ok: false, error: 'lat & lng required' }, { status: 400 });
26	  }
27	
28	  // 1. Pull the oblique screenshot from /api/aerial?tilted=1.
29	  const origin = req.nextUrl.origin;
30	  const aerialUrl = `${origin}/api/aerial?lat=${lat}&lng=${lng}&zoom=${body.zoom ?? 20}&tilted=1`;
31	  const aerialRes = await fetch(aerialUrl);
32	  if (!aerialRes.ok) {
33	    return NextResponse.json(
34	      { ok: false, error: `aerial screenshot failed (${aerialRes.status})` },
35	      { status: 502 },
36	    );
37	  }
38	  const buf = Buffer.from(await aerialRes.arrayBuffer());
39	
40	  // 2. Run GPT Image 2 to clean / isolate the building.
