1	// Top-down (default) or 3D-tilted (?tilted=1) satellite view for a lat/lng or
2	// street address. Top-down → Google Static Maps proxy. Tilted → Cesium +
3	// Google Photorealistic 3D Tiles rendered headlessly via Playwright.
4	
5	import { NextResponse, type NextRequest } from 'next/server';
6	
7	export const runtime = 'nodejs';
8	
9	const MAPS_KEY = process.env.GOOGLE_MAPS_API_KEY ?? '';
10	const GEOCODE_URL = 'https://maps.googleapis.com/maps/api/geocode/json';
11	const STATIC_URL = 'https://maps.googleapis.com/maps/api/staticmap';
12	
13	export async function GET(req: NextRequest) {
14	  if (!MAPS_KEY) {
15	    return NextResponse.json({ error: 'GOOGLE_MAPS_API_KEY not configured' }, { status: 500 });
16	  }
17	
18	  const { searchParams } = new URL(req.url);
19	  const latParam = parseFloat(searchParams.get('lat') ?? '');
20	  const lngParam = parseFloat(searchParams.get('lng') ?? '');
21	  const address = searchParams.get('address');
22	  const zoom = clamp(parseInt(searchParams.get('zoom') ?? '20', 10), 17, 21);
23	  const tilted = searchParams.get('tilted') === '1';
24	
25	  let lat: number;
26	  let lng: number;
27	  let resolvedAddress = address ?? '';
28	
29	  if (Number.isFinite(latParam) && Number.isFinite(lngParam)) {
30	    lat = latParam;
31	    lng = lngParam;
32	  } else if (address) {
33	    const geo = await fetch(
34	      `${GEOCODE_URL}?address=${encodeURIComponent(address)}&key=${MAPS_KEY}`,
35	    );
36	    const json = await geo.json();
37	    if (json.status !== 'OK' || !json.results?.[0]) {
38	      return NextResponse.json(
39	        { error: 'Address not found', status: json.status },
40	        { status: 404 },
41	      );
42	    }
43	    lat = json.results[0].geometry.location.lat;
44	    lng = json.results[0].geometry.location.lng;
45	    resolvedAddress = json.results[0].formatted_address;
46	  } else {
47	    return NextResponse.json({ error: 'Provide lat & lng OR address' }, { status: 400 });
48	  }
49	
50	  let buf: Buffer;
51	
52	  if (tilted) {
53	    // Render the Cesium oblique page in headless Chromium and screenshot it.
54	    const origin = req.nextUrl.origin;
55	    // Look up the local ground elevation (in metres above WGS84 ellipsoid)
56	    // via Google's Elevation API. This is then forwarded to /oblique so the
57	    // marker can be placed AT building-roof height — without it, the dot
58	    // sits at the wrong altitude and the oblique parallax shifts it off the
59	    // visible roof. The API returns orthometric height (above MSL/EGM2008)
60	    // so we add the typical European geoid undulation (~45 m) to convert it
61	    // to ellipsoidal height, then add ~8 m for typical European roof height.
62	    let elevAboveEllipsoid: number | null = null;
63	    try {
64	      const er = await fetch(
65	        `https://maps.googleapis.com/maps/api/elevation/json?locations=${lat},${lng}&key=${MAPS_KEY}`,
66	      );
67	      const ej = (await er.json()) as { results?: Array<{ elevation?: number }> };
68	      const orthometric = ej.results?.[0]?.elevation;
69	      if (typeof orthometric === 'number') {
70	        // Geoid undulation rough constant for Western/Central Europe.
71	        // (Precise per-location N would need a geoid model; +45 is fine here.)
72	        elevAboveEllipsoid = orthometric + 45;
73	      }
74	    } catch {
75	      /* ignore — falls back to default in /oblique */
76	    }
77	    const elevParam = elevAboveEllipsoid !== null ? `&elev=${elevAboveEllipsoid}` : '';
78	    const obliqueUrl =
79	      `${origin}/oblique?lat=${lat}&lng=${lng}&zoom=${zoom}&heading=0&tilt=40&height=50${elevParam}`;
80	    try {
81	      const { chromium } = await import('playwright');
82	      const browser = await chromium.launch({ headless: true });
83	      const ctx = await browser.newContext({
84	        viewport: { width: 1280, height: 1280 },
85	        deviceScaleFactor: 1,
86	      });
87	      const page = await ctx.newPage();
88	      await page.goto(obliqueUrl, { waitUntil: 'domcontentloaded', timeout: 30_000 });
89	      await page
90	        .waitForFunction(
91	          () => ((window as unknown as { __obliqueStable?: number }).__obliqueStable ?? 0) > 25,
92	          null,
93	          { timeout: 60_000, polling: 250 },
94	        )
95	        .catch(() => {});
96	      await page.waitForTimeout(800);
97	      await page
98	        .evaluate(() => {
99	          for (const el of document.querySelectorAll('nextjs-portal, [data-nextjs-toast]')) {
100	            (el as HTMLElement).style.display = 'none';
101	          }
102	        })
103	        .catch(() => {});
104	      buf = await page.screenshot({ fullPage: false });
105	      await browser.close();
106	    } catch (err) {
107	      return NextResponse.json(
108	        { error: 'Oblique render failed', detail: String(err) },
109	        { status: 502 },
110	      );
111	    }
112	  } else {
113	    const staticUrl =
114	      `${STATIC_URL}?center=${lat},${lng}` +
115	      `&zoom=${zoom}&scale=2&size=640x640&maptype=satellite&format=png` +
116	      `&markers=color:red%7Csize:tiny%7C${lat},${lng}` +
117	      `&key=${MAPS_KEY}`;
118	    const imgRes = await fetch(staticUrl);
119	    if (!imgRes.ok) {
